use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{Transaction}

/// Owner can rotate their key: new_commitment = hash(new_owner)
fn new_commitment(new_owner: ByteArray) -> ByteArray {
  blake2b_224(new_owner)
}

/// Rotation is valid if old owner authorises AND new commitment is correct
fn rotation_valid(
  old_owner:      ByteArray,
  old_commitment: ByteArray,
  new_owner:      ByteArray,
  new_commitment_: ByteArray,
) -> Bool {
  blake2b_224(old_owner) == old_commitment
    && blake2b_224(new_owner) == new_commitment_
}

// ── Datum / Redeemer types ────────────────────────────────────────────────────

pub type VaultDatum {
  owner_commitment: ByteArray,
}

pub type VaultRedeemer {
  old_owner: ByteArray,
  new_owner: ByteArray,
}

// ── Validator ─────────────────────────────────────────────────────────────────

validator param_vault_rotation {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _input: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let VaultRedeemer { old_owner, new_owner } = redeemer
    let expected_new_com = new_commitment(new_owner)
    let old_owner_authorises =
      list.any(
        self.extra_signatories,
        fn(sig) { sig == blake2b_224(old_owner) },
      )
    rotation_valid(old_owner, d.owner_commitment, new_owner, expected_new_com)
      && old_owner_authorises
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

use aiken/collection/list

test prop_rotation_valid_with_correct_keys(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  rotation_valid(old_owner, old_com, new_owner, new_com)
}

test prop_wrong_old_owner_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  !rotation_valid(#"deadbeef", old_com, new_owner, new_com)
}

test prop_new_commitment_correct(
  owner via cfuzz.verification_key_hash(),
) {
  new_commitment(owner) == blake2b_224(owner)
}

test prop_different_owners_differ(
  owner via cfuzz.verification_key_hash(),
) {
  // owner vs its hash — almost certainly different lengths, different hashes
  let alt = bytearray.concat(owner, #"ff")
  new_commitment(owner) != new_commitment(alt)
}

use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{Transaction}

/// Hash a sorted list of signers into a single commitment
/// Sort by prepending each then folding (deterministic ordering assumed)
fn signers_hash(signer_a: ByteArray, signer_b: ByteArray) -> ByteArray {
  blake2b_224(bytearray.concat(signer_a, signer_b))
}

/// Both signers must match the commitment
fn multisig_params_valid(
  signer_a: ByteArray,
  signer_b: ByteArray,
  expected: ByteArray,
) -> Bool {
  signers_hash(signer_a, signer_b) == expected
}

/// Commitment is order-sensitive (concat is not commutative)
fn order_matters(a: ByteArray, b: ByteArray) -> Bool {
  a == b || signers_hash(a, b) != signers_hash(b, a)
}

// ── Validator ────────────────────────────────────────────────────────────────

pub type VaultDatum {
  signer_a: ByteArray,
  signer_b: ByteArray,
  commitment: ByteArray,
}

pub type VaultRedeemer {
  signer_a: ByteArray,
  signer_b: ByteArray,
}

validator param_vault_multisig_hash {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _output_reference: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let signer_a_present =
      list.any(self.extra_signatories, fn(s) { s == d.signer_a })
    let signer_b_present =
      list.any(self.extra_signatories, fn(s) { s == d.signer_b })
    let params_ok =
      multisig_params_valid(redeemer.signer_a, redeemer.signer_b, d.commitment)
    let redeemer_matches =
      redeemer.signer_a == d.signer_a && redeemer.signer_b == d.signer_b
    params_ok && redeemer_matches && signer_a_present && signer_b_present
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

use aiken/collection/list

test prop_correct_signers_match(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  multisig_params_valid(s1, s2, expected)
}

test prop_swapped_signers_fail(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  // swapping signers should fail unless s1 == s2
  s1 == s2 || !multisig_params_valid(s2, s1, expected)
}

test prop_order_sensitivity(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  order_matters(s1, s2)
}

test prop_wrong_signer_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  !multisig_params_valid(s1, bytearray.concat(s2, #"00"), expected)
}

use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

/// Burning stablecoin is only valid when collateral is being proportionally returned
/// collateral_returned >= burn_amount * stability_fee / 100
fn burn_returns_collateral(
  burn_amount: Int,
  collateral_returned: Int,
  stability_fee: Int,
) -> Bool {
  burn_amount > 0
    && collateral_returned >= burn_amount * stability_fee / 100
}

/// Excess collateral return is allowed (over-repayment)
fn over_return_allowed(
  burn_amount: Int,
  collateral_returned: Int,
  stability_fee: Int,
) -> Bool {
  burn_returns_collateral(burn_amount, collateral_returned, stability_fee)
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_exact_return_valid(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(100, 200)),
) {
  let (burn, fee) = vals
  let collateral = burn * fee / 100
  burn_returns_collateral(burn, collateral, fee)
}

test prop_over_return_valid(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(100, 200)),
) {
  let (burn, fee) = vals
  let collateral = burn * fee / 100 + 1
  over_return_allowed(burn, collateral, fee)
}

test prop_zero_burn_rejected(
  fee via fuzz.int_between(100, 200),
) {
  !burn_returns_collateral(0, 0, fee)
}

test prop_under_return_rejected(
  vals via fuzz.both(fuzz.int_between(2, 1000), fuzz.int_between(101, 200)),
) {
  let (burn, fee) = vals
  let required = burn * fee / 100
  !burn_returns_collateral(burn, required - 1, fee)
}

/// Redeemer carries the burn amount, collateral returned, and the stability fee
pub type BurnRedeemer {
  burn_amount: Int,
  collateral_returned: Int,
  stability_fee: Int,
}

validator stable_burn_gate(policy_id: PolicyId) {
  mint(redeemer: BurnRedeemer, _policy: PolicyId, self: Transaction) {
    let BurnRedeemer { burn_amount, collateral_returned, stability_fee } =
      redeemer
    // Only allow negative mints (burns) when collateral is proportionally returned
    let burn_ok =
      over_return_allowed(burn_amount, collateral_returned, stability_fee)
    // Confirm the policy being minted under matches the guarded policy
    let policy_matches = policy_id == _policy
    burn_ok && policy_matches && (self.mint != assets.zero)
  }

  else(_) {
    fail
  }
}

use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

/// Global debt ceiling: total minted stablecoin must not exceed the cap
fn under_debt_ceiling(
  current_supply: Int,
  mint_amount: Int,
  debt_ceiling: Int,
) -> Bool {
  mint_amount > 0 && current_supply + mint_amount <= debt_ceiling
}

/// Remaining mintable supply
fn remaining_capacity(current_supply: Int, debt_ceiling: Int) -> Int {
  if debt_ceiling > current_supply {
    debt_ceiling - current_supply
  } else {
    0
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_mint_under_ceiling(
  vals via fuzz.both(fuzz.int_between(0, 500), fuzz.int_between(501, 1000)),
) {
  let (supply, ceiling) = vals
  under_debt_ceiling(supply, 1, ceiling)
}

test prop_mint_at_ceiling_rejected(
  ceiling via fuzz.int_between(1, 1000),
) {
  !under_debt_ceiling(ceiling, 1, ceiling)
}

test prop_remaining_capacity_correct(
  vals via fuzz.both(fuzz.int_between(0, 500), fuzz.int_between(501, 1000)),
) {
  let (supply, ceiling) = vals
  remaining_capacity(supply, ceiling) == ceiling - supply
}

test prop_no_capacity_at_ceiling(
  ceiling via fuzz.int_between(1, 1000),
) {
  remaining_capacity(ceiling, ceiling) == 0
}

/// Redeemer carries the current circulating supply and the debt ceiling
pub type DebtCeilingRedeemer {
  current_supply: Int,
  debt_ceiling: Int,
}

validator stable_debt_ceiling {
  mint(redeemer: DebtCeilingRedeemer, policy_id: PolicyId, self: Transaction) {
    let DebtCeilingRedeemer { current_supply, debt_ceiling } = redeemer

    // Sum the mint amount for tokens under this policy
    let mint_amount =
      assets.tokens(self.mint, policy_id)
        |> assets.reduce(_, 0, fn(_, qty, acc) { acc + qty })

    // Verify capacity exists before minting
    let capacity = remaining_capacity(current_supply, debt_ceiling)

    capacity > 0 && under_debt_ceiling(current_supply, mint_amount, debt_ceiling)
  }

  else(_) {
    fail
  }
}

use aiken/fuzz
use cardano/transaction.{Transaction, InlineDatum}
use cardano/assets

/// Price improvement: buyer gets filled at a price better than or equal to their limit
fn buyer_price_ok(execution_price: Int, limit_price: Int) -> Bool {
  execution_price <= limit_price
}

/// Seller also gets filled at or above their ask
fn seller_price_ok(execution_price: Int, ask_price: Int) -> Bool {
  execution_price >= ask_price
}

/// Both sides satisfied by execution price
fn prices_satisfied(
  execution_price: Int,
  buyer_limit: Int,
  seller_ask: Int,
) -> Bool {
  buyer_price_ok(execution_price, buyer_limit)
    && seller_price_ok(execution_price, seller_ask)
}

// ── Datum / Redeemer types ────────────────────────────────────────────────────

pub type OrderDatum {
  buyer_limit: Int
  seller_ask: Int
}

pub type OrderRedeemer {
  execution_price: Int
}

// ── Validator ─────────────────────────────────────────────────────────────────

validator order_price_improvement {
  spend(
    datum: Option<OrderDatum>,
    redeemer: OrderRedeemer,
    _output_reference: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let OrderRedeemer { execution_price } = redeemer
    let total_in =
      assets.lovelace_of(
        self.inputs
          |> list.foldl(
              assets.zero,
              fn(inp, acc) { assets.merge(acc, inp.output.value) },
            ),
      )
    let _ = total_in
    prices_satisfied(execution_price, d.buyer_limit, d.seller_ask)
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_midpoint_satisfies_both(
  vals via fuzz.both(fuzz.int_between(1, 500), fuzz.int_between(501, 1000)),
) {
  let (ask, limit) = vals
  let mid = (ask + limit) / 2
  prices_satisfied(mid, limit, ask)
}

test prop_buyer_limit_violated(
  vals via fuzz.both(fuzz.int_between(101, 200), fuzz.int_between(1, 100)),
) {
  let (execution, limit) = vals
  !buyer_price_ok(execution, limit)
}

test prop_seller_ask_violated(
  vals via fuzz.both(fuzz.int_between(1, 100), fuzz.int_between(101, 200)),
) {
  let (execution, ask) = vals
  !seller_price_ok(execution, ask)
}

test prop_equal_prices_satisfied(
  price via fuzz.int_between(1, 1000),
) {
  prices_satisfied(price, price, price)
}

use aiken/fuzz
use cardano/transaction.{Transaction, InlineDatum}
use cardano/assets

/// Protocol fee collected on each fill (in bps)
fn fill_fee(fill_qty: Int, price: Int, fee_bps: Int) -> Int {
  fill_qty * price * fee_bps / 10000
}

/// Net proceeds to seller after fee deduction
fn seller_proceeds(fill_qty: Int, price: Int, fee_bps: Int) -> Int {
  fill_qty * price - fill_fee(fill_qty, price, fee_bps)
}

/// Fee is non-negative and less than gross proceeds
fn fee_valid(fill_qty: Int, price: Int, fee_bps: Int) -> Bool {
  let gross = fill_qty * price
  let fee   = fill_fee(fill_qty, price, fee_bps)
  fee >= 0 && fee < gross
}

// ── Datum / Redeemer types ────────────────────────────────────────────────────

pub type OrderDatum {
  price: Int,
  fee_bps: Int,
  seller_pkh: ByteArray,
}

pub type FillRedeemer {
  fill_qty: Int,
}

// ── Validator ─────────────────────────────────────────────────────────────────

validator order_fee_collection {
  spend(
    datum: Option<OrderDatum>,
    redeemer: FillRedeemer,
    _own_ref: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let FillRedeemer { fill_qty } = redeemer

    // Validate the fee parameters are sound
    expect fee_valid(fill_qty, d.price, d.fee_bps)

    // Calculate expected net proceeds to seller
    let expected_proceeds = seller_proceeds(fill_qty, d.price, d.fee_bps)

    // Verify seller receives at least the net proceeds in lovelace
    let seller_payment =
      self.outputs
        |> list.filter(
            fn(o) {
              when o.address.payment_credential is {
                cardano/address.VerificationKey(vk) -> vk == d.seller_pkh
                _ -> False
              }
            },
          )
        |> list.foldl(
            0,
            fn(o, acc) { acc + assets.lovelace_of(o.value) },
          )

    seller_payment >= expected_proceeds
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_zero_fee_bps_no_fee(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  fill_fee(qty, price, 0) == 0
}

test prop_seller_receives_less_than_gross(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 100)),
) {
  let (qty, fee_bps) = vals
  let price = 100
  seller_proceeds(qty, price, fee_bps) < qty * price
}

test prop_fee_valid_for_standard_rate(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  fee_valid(qty, price, 30)
}

test prop_seller_proceeds_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 9999)),
) {
  let (qty, fee_bps) = vals
  seller_proceeds(qty, 100, fee_bps) >= 0
}

use aiken/fuzz
use cardano/transaction.{Transaction, InlineDatum}
use cardano/assets

/// Net position after matching N buy orders against M sell orders
/// Simplified: single buyer/seller, net_qty = buy_qty - sell_qty
fn net_position(buy_qty: Int, sell_qty: Int) -> Int {
  buy_qty - sell_qty
}

/// Settlement amount for net position at clearing price
fn settlement_amount(net_qty: Int, clearing_price: Int) -> Int {
  if net_qty >= 0 {
    net_qty * clearing_price
  } else {
    -net_qty * clearing_price
  }
}

/// Fully netted position has zero settlement
fn is_fully_netted(buy_qty: Int, sell_qty: Int) -> Bool {
  buy_qty == sell_qty
}

pub type OrderDatum {
  buy_qty: Int,
  sell_qty: Int,
  clearing_price: Int,
  beneficiary: ByteArray,
}

pub type OrderRedeemer {
  Settle
  Cancel
}

validator order_netting {
  spend(
    datum: Option<OrderDatum>,
    redeemer: OrderRedeemer,
    _output_ref: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Cancel -> {
        let net = net_position(d.buy_qty, d.sell_qty)
        is_fully_netted(d.buy_qty, d.sell_qty) || net != 0
      }
      Settle -> {
        let net = net_position(d.buy_qty, d.sell_qty)
        let owed = settlement_amount(net, d.clearing_price)
        let total_out =
          assets.lovelace_of(
            self.outputs
              |> list.foldl(
                  assets.zero,
                  fn(o, acc) { assets.merge(acc, o.value) },
                ),
          )
        total_out >= owed
      }
    }
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_equal_buys_sells_net_zero(
  qty via fuzz.int_between(1, 1000),
) {
  net_position(qty, qty) == 0 && is_fully_netted(qty, qty)
}

test prop_net_long_positive(
  vals via fuzz.both(fuzz.int_between(101, 1000), fuzz.int_between(1, 100)),
) {
  let (buy, sell) = vals
  net_position(buy, sell) > 0
}

test prop_settlement_zero_when_netted(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  settlement_amount(net_position(qty, qty), price) == 0
}

test prop_settlement_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (net, price) = vals
  settlement_amount(net, price) >= 0
}

use aiken/collection/list
use aiken/fuzz
use cardano/address
use cardano/assets.{PolicyId}
use cardano/fuzz as cfuzz
use cardano/transaction.{InlineDatum, NoDatum, Output}

/// Continuing output must carry the NFT and have an InlineDatum
fn has_inline_datum(output: Output) -> Bool {
  when output.datum is {
    InlineDatum(_) -> True
    _              -> False
  }
}

fn thread_output_valid(
  output:      Output,
  auth_policy: PolicyId,
  auth_name:   ByteArray,
) -> Bool {
  assets.quantity_of(output.value, auth_policy, auth_name) == 1
    && has_inline_datum(output)
}

fn find_thread_output(
  outputs:     List<Output>,
  auth_policy: PolicyId,
  auth_name:   ByteArray,
) -> Bool {
  list.any(outputs, fn(o) { thread_output_valid(o, auth_policy, auth_name) })
}

// ── Validator ────────────────────────────────────────────────────────────────

pub type ThreadDatum {
  auth_policy: PolicyId,
  auth_name: ByteArray,
}

validator thread_nft_datum_update {
  spend(
    datum: Option<ThreadDatum>,
    _redeemer: Data,
    _utxo: cardano/transaction.OutputReference,
    self: cardano/transaction.Transaction,
  ) {
    expect Some(d) = datum
    find_thread_output(self.outputs, d.auth_policy, d.auth_name)
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_output_with_nft_and_inline_datum_valid(
  vals via fuzz.both(cfuzz.policy_id(), cfuzz.asset_name()),
) {
  let (policy, name) = vals
  let val = assets.from_asset(policy, name, 1)
  let out = Output {
    address:          address.from_verification_key(#"aabb"),
    value:            val,
    datum:            InlineDatum(42),
    reference_script: None,
  }
  thread_output_valid(out, policy, name)
}

test prop_output_no_datum_rejected(
  vals via fuzz.both(cfuzz.policy_id(), cfuzz.asset_name()),
) {
  let (policy, name) = vals
  let val = assets.from_asset(policy, name, 1)
  let out = Output {
    address:          address.from_verification_key(#"aabb"),
    value:            val,
    datum:            NoDatum,
    reference_script: None,
  }
  !thread_output_valid(out, policy, name)
}

test prop_find_thread_output_true(
  vals via fuzz.both(cfuzz.policy_id(), cfuzz.asset_name()),
) {
  let (policy, name) = vals
  let val = assets.from_asset(policy, name, 1)
  let out = Output {
    address:          address.from_verification_key(#"aabb"),
    value:            val,
    datum:            InlineDatum(0),
    reference_script: None,
  }
  find_thread_output([out], policy, name)
}

test prop_find_thread_output_empty_false() {
  !find_thread_output([], #"aabb", #"ccdd")
}

use aiken/collection/list
use aiken/fuzz
use cardano/transaction.{Transaction}

/// All indices in the list are unique (no duplicates)
fn all_unique(indices: List<Int>) -> Bool {
  when indices is {
    []           -> True
    [head, ..tail] ->
      !list.has(tail, head) && all_unique(tail)
  }
}

/// Indices are within bounds [0, max_idx)
fn all_in_bounds(indices: List<Int>, max_idx: Int) -> Bool {
  list.all(indices, fn(i) { i >= 0 && i < max_idx })
}

/// Valid index set: unique and in bounds
fn valid_index_set(indices: List<Int>, max_idx: Int) -> Bool {
  all_unique(indices) && all_in_bounds(indices, max_idx)
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_empty_indices_unique() {
  all_unique([])
}

test prop_single_index_unique(
  i via fuzz.int_between(0, 100),
) {
  all_unique([i])
}

test prop_two_same_not_unique(
  i via fuzz.int_between(0, 100),
) {
  !all_unique([i, i])
}

test prop_valid_index_set_accepted(
  max_idx via fuzz.int_between(3, 10),
) {
  valid_index_set([0, 1, 2], max_idx)
}

// ── Validator ─────────────────────────────────────────────────────────────────

pub type BatchRedeemer {
  indices: List<Int>
  max_idx: Int
}

validator batch_unique_indices {
  spend(
    _datum: Option<Data>,
    redeemer: BatchRedeemer,
    _utxo: Data,
    _self: Transaction,
  ) {
    let BatchRedeemer { indices, max_idx } = redeemer
    expect max_idx > 0
    valid_index_set(indices, max_idx)
  }

  else(_) {
    fail
  }
}
